#include<bits/stdc++.h>
using namespace std;
int a[5000010],s[5000010],n,k;
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        int sum=0;
        for(int j=20;j>=0;j--)
        {
            if(((k>>j)&1)&&((a[i]>>j)&1))
            {
                s[sum+(1<<j)]++;
                s[sum+(1<<(j+1))]--;
            }
            else if((k>>j)&1)
            {
                s[sum]++;
                s[sum+(1<<j)]--;
                sum+=(1<<j);
            }
            else if((a[i]>>j)&1)
            {
                sum+=(1<<j);
            }
        }
        s[sum]++;
        s[sum+1]--;
    }
    int ans=0;
    for(int i=0;i<=(1<<20);i++)
    {
        if(i>0)
        {
            s[i]+=s[i-1];
        }
        ans=max(ans,s[i]);
    }
    printf("%d",ans);
    return 0;
}
